diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 86de89595957..a6e954468644 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -29,7 +29,7 @@
 #include "llvm/IR/IRBuilder.h"
 #include "llvm/IR/InstrTypes.h"
 #include "llvm/IR/Instructions.h"
-#include "llvm/IR/Module.h"
+#include "llvm/IR/Module.h"\n#include "llvm/IR/ConstantRange.h"
 #include "llvm/IR/PatternMatch.h"
 #include "llvm/IR/Verifier.h"
 #include "llvm/Pass.h"
@@ -271,8 +271,8 @@ class ConstraintInfo {

   const DataLayout &DL;

-public:
-  ConstraintInfo(const DataLayout &DL, ArrayRef<Value *> FunctionArgs)
+  ConstraintInfo(const DataLayout &DL, const Function &F,
+                 ArrayRef<Value *> FunctionArgs)
       : UnsignedCS(FunctionArgs), SignedCS(FunctionArgs), DL(DL) {
     auto &Value2Index = getValue2Index(false);
     // Add Arg > -1 constraints to unsigned system for all function arguments.
@@ -282,6 +282,33 @@ public:
       VarPos.Coefficients[Value2Index[Arg]] = -1;
       UnsignedCS.addVariableRow(VarPos.Coefficients);
     }
+    // Add range attribute constraints for function arguments.
+    // We use a dummy stack for constraints that are always in scope.
+    SmallVector<StackEntry, 4> DummyStack;
+    for (Argument &Arg : F.args()) {
+      unsigned ArgNo = Arg.getArgNo();
+      if (ArgNo >= FunctionArgs.size())
+        continue;
+      Value *V = FunctionArgs[ArgNo];
+      Attribute RangeAttr = F.getParamAttr(ArgNo, Attribute::Range);
+      if (RangeAttr.isValid()) {
+        const ConstantRange &CR = RangeAttr.getRange();
+        // Add lower bound constraint if the range has a minimum.
+        if (!CR.isFullSet() && !CR.getSignedMin().isMinSignedValue()) {
+          // Arg >= CR.getSignedMin()
+          addFact(CmpInst::ICMP_SGE, V,
+                  ConstantInt::get(V->getType(), CR.getSignedMin()),
+                  0, 0, DummyStack);
+        }
+        // Add upper bound constraint if the range has a maximum.
+        if (!CR.isFullSet() && !CR.getSignedMax().isMaxSignedValue()) {
+          // Arg <= CR.getSignedMax()
+          addFact(CmpInst::ICMP_SLE, V,
+                  ConstantInt::get(V->getType(), CR.getSignedMax()),
+                  0, 0, DummyStack);
+        }
+      }
+    }
   }

   DenseMap<Value *, unsigned> &getValue2Index(bool Signed) {
@@ -545,6 +572,12 @@ static Decomposition decompose(Value *V,
         return Result;
       }
     }
+    if (match(V, m_NSWSub(m_Value(Op0), m_Value(Op1)))) {
+      auto ResA = decompose(Op0, Preconditions, IsSigned, DL);
+      auto ResB = decompose(Op1, Preconditions, IsSigned, DL);
+      ResA.sub(ResB);
+      return ResA;
+    }

     return {V, IsKnownNonNegative};
   }
@@ -1701,7 +1734,7 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
   SmallVector<Value *> FunctionArgs;
   for (Value &Arg : F.args())
     FunctionArgs.push_back(&Arg);
-  ConstraintInfo Info(F.getDataLayout(), FunctionArgs);
+  ConstraintInfo Info(F.getDataLayout(), F, FunctionArgs);
   State S(DT, LI, SE);
   std::unique_ptr<Module> ReproducerModule(
       DumpReproducers ? new Module(F.getName(), F.getContext()) : nullptr);

